content:
:root {
    --neon-cyan: #00f3ff;
    --neon-pink: #ff00ff;
    --neon-red: #ff003c;
    --bg-dark: #0d0208;
    --box-bg: rgba(13, 2, 8, 0.85);
    --font-main: 'Roboto Mono', monospace;
    --font-header: 'Orbitron', sans-serif;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body.cyber-theme {
    background-color: var(--bg-dark);
    color: #fff;
    font-family: var(--font-main);
    height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    overflow: hidden;
    position: relative;
}

/* Scanlines Overlay */
.scanlines {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(
        rgba(18, 16, 16, 0) 50%,
        rgba(0, 0, 0, 0.25) 50%
    ),
    linear-gradient(
        90deg,
        rgba(255, 0, 0, 0.06),
        rgba(0, 255, 0, 0.02),
        rgba(0, 0, 255, 0.06)
    );
    background-size: 100% 4px, 3px 100%;
    pointer-events: none;
    z-index: 100;
}

/* Layout Container */
.login-container {
    width: 450px;
    z-index: 10;
    padding: 20px;
    border: 2px solid var(--neon-cyan);
    background: var(--box-bg);
    box-shadow: 0 0 20px rgba(0, 243, 255, 0.2), inset 0 0 10px rgba(0, 243, 255, 0.1);
    position: relative;
}

.login-container::before {
    content: '';
    position: absolute;
    top: -5px;
    left: -5px;
    right: -5px;
    bottom: -5px;
    border: 1px solid var(--neon-pink);
    z-index: -1;
    opacity: 0.3;
}

/* Glitch Text Effect */
.glitch-wrapper {
    text-align: center;
    margin-bottom: 30px;
}

.glitch {
    font-family: var(--font-header);
    font-size: 2.5rem;
    font-weight: 700;
    text-transform: uppercase;
    position: relative;
    color: #fff;
    text-shadow: 0.05em 0 0 var(--neon-red), -0.025em -0.05em 0 var(--neon-cyan),
                 0.025em 0.05em 0 var(--neon-pink);
    animation: glitch 500ms infinite;
}

@keyframes glitch {
    0% { text-shadow: 0.05em 0 0 var(--neon-red), -0.025em -0.05em 0 var(--neon-cyan), 0.025em 0.05em 0 var(--neon-pink); }
    14% { text-shadow: 0.05em 0 0 var(--neon-red), -0.025em -0.05em 0 var(--neon-cyan), 0.025em 0.05em 0 var(--neon-pink); }
    15% { text-shadow: -0.05em -0.025em 0 var(--neon-red), 0.025em 0.025em 0 var(--neon-cyan), -0.05em -0.05em 0 var(--neon-pink); }
    49% { text-shadow: -0.05em -0.025em 0 var(--neon-red), 0.025em 0.025em 0 var(--neon-cyan), -0.05em -0.05em 0 var(--neon-pink); }
    50% { text-shadow: 0.025em 0.05em 0 var(--neon-red), 0.05em 0 0 var(--neon-cyan), 0 -0.05em 0 var(--neon-pink); }
    99% { text-shadow: 0.025em 0.05em 0 var(--neon-red), 0.05em 0 0 var(--neon-cyan), 0 -0.05em 0 var(--neon-pink); }
    100% { text-shadow: -0.025em 0 0 var(--neon-red), -0.025em -0.025em 0 var(--neon-cyan), -0.025em -0.05em 0 var(--neon-pink); }
}

/* Terminal Header */
.terminal-header {
    display: flex;
    justify-content: space-between;
    font-size: 0.7rem;
    border-bottom: 1px solid var(--neon-cyan);
    padding-bottom: 5px;
    margin-bottom: 20px;
    color: var(--neon-cyan);
    letter-spacing: 2px;
}

.status-online {
    color: #00ff9f;
    text-shadow: 0 0 5px #00ff9f;
}

.prompt {
    font-size: 0.8rem;
    color: var(--neon-pink);
    margin-bottom: 20px;
    text-transform: uppercase;
}

/* Form Styling */
.cyber-form {
    display: flex;
    flex-direction: column;
    gap: 25px;
}

.input-wrapper {
    position: relative;
    display: flex;
    flex-direction: column;
}

.input-wrapper label {
    font-size: 0.75rem;
    color: var(--neon-cyan);
    margin-bottom: 8px;
    letter-spacing: 1px;
}

.input-wrapper input {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid rgba(0, 243, 255, 0.3);
    padding: 12px 15px;
    color: #fff;
    font-family: var(--font-main);
    outline: none;
    transition: all 0.3s ease;
}

.input-wrapper input:focus {
    border-color: var(--neon-cyan);
    background: rgba(0, 243, 255, 0.1);
    box-shadow: 0 0 10px rgba(0, 243, 255, 0.2);
}

.input-glow {
    position: absolute;
    bottom: 0;
    left: 0;
    width: 0%;
    height: 2px;
    background: var(--neon-cyan);
    transition: width 0.4s ease;
}

.input-wrapper input:focus + .input-glow {
    width: 100%;
}

/* Login Button with Glitch */
.submit-btn {
    position: relative;
    padding: 15px;
    background: var(--neon-cyan);
    border: none;
    color: #000;
    font-family: var(--font-header);
    font-weight: bold;
    text-transform: uppercase;
    cursor: pointer;
    clip-path: polygon(92% 0, 100% 25%, 100% 100%, 8% 100%, 0% 75%, 0 0);
    transition: transform 0.2s;
}

.submit-btn:active {
    transform: scale(0.98);
}

.submit-btn:hover {
    background: var(--neon-pink);
    color: #fff;
}

.submit-btn:hover .btn-glitch-layer {
    display: block;
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: var(--neon-pink);
    animation: btn-glitch 0.3s cubic-bezier(.25, .46, .45, .94) both infinite;
    z-index: -1;
}

@keyframes btn-glitch {
    0% { transform: translate(0); }
    20% { transform: translate(-3px, 3px); }
    40% { transform: translate(-3px, -3px); }
    60% { transform: translate(3px, 3px); }
    80% { transform: translate(3px, -3px); }
    100% { transform: translate(0); }
}

/* Error Container */
.error-container {
    background: rgba(255, 0, 60, 0.1);
    border-left: 4px solid var(--neon-red);
    padding: 10px;
    margin-bottom: 20px;
    animation: pulse-red 2s infinite;
}

.error-header {
    font-weight: bold;
    color: var(--neon-red);
    font-size: 0.8rem;
    margin-bottom: 5px;
}

.error-body {
    font-size: 0.75rem;
    color: #ff99aa;
}

@keyframes pulse-red {
    0% { box-shadow: 0 0 0px rgba(255, 0, 60, 0); }
    50% { box-shadow: 0 0 10px rgba(255, 0, 60, 0.3); }
    100% { box-shadow: 0 0 0px rgba(255, 0, 60, 0); }
}

/* Footer Decor */
.login-footer {
    margin-top: 30px;
}

.footer-deco-line {
    height: 1px;
    background: linear-gradient(90deg, transparent, var(--neon-cyan), transparent);
    margin-bottom: 10px;
}

.footer-info {
    display: flex;
    justify-content: space-between;
    font-size: 0.6rem;
    color: rgba(255, 255, 255, 0.4);
    text-transform: uppercase;
    letter-spacing: 1px;
}

/* Processing state for JS */
.submit-btn.processing {
    filter: grayscale(1);
    pointer-events: none;
    animation: blink 0.5s infinite;
}

@keyframes blink {
    50% { opacity: 0.5; }
}
